#include "bno055.h"
#include <Wire.h>
#include <Adafruit_BNO055.h>
#include <Adafruit_Sensor.h>
static Adafruit_BNO055 bno(55,0x28);
static float _h=0,_r=0,_p=0,_t=0;static uint8_t _cal=0;static unsigned long _l=0;
void bno055_setup(){Wire.begin();if(!bno.begin()){Serial.println("[bno055] Fail!");return;}bno.setExtCrystalUse(true);Serial.println("[bno055] OK");}
void bno055_loop(){if(millis()-_l<100)return;_l=millis();imu::Vector<3> euler=bno.getVector(Adafruit_BNO055::VECTOR_EULER);_h=euler.x();_r=euler.y();_p=euler.z();_t=bno.getTemp();uint8_t s,g,a,m;bno.getCalibration(&s,&g,&a,&m);_cal=s;}
float bno055_get_heading(){return _h;}
float bno055_get_roll(){return _r;}
float bno055_get_pitch(){return _p;}
float bno055_get_temp(){return _t;}
uint8_t bno055_get_calibration(){return _cal;}
